import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office - Quote", () => {
  it.todo("should return 5 G for an empty item list -- premium 5");

  it.todo("should return 105 G for a single sword -- 100 base + 5 fee");

  it.todo("should return 65 G for a single amulet -- 60 base + 5 fee");

  it.todo("should return 85 G for a single staff -- 80 base + 5 fee");

  it.todo("should return 45 G for a single potion -- 40 base + 5 fee");

  it.todo("should return 30 G for a single rune -- 25 base + 5 fee");

  it.todo("should return 55 G for 2 runes -- 50 base + 5 fee");

  it.todo("should return 65 G for 3 runes (block applies) -- 60 block + 5 fee");

  it.todo("should return 105 G for 4 runes (no block, requires exactly 3) -- 100 base + 5 fee");

  it.todo("should return 180 G for 7 runes -- 175 base + 5 fee");

  it.todo("should return 80 G for 2 runes + 1 moonstone (no block, different types) -- 75 base + 5 fee");

  it.todo("should return 125 G for 3 runes + 3 moonstones (two separate blocks) -- 120 base + 5 fee");

  it.todo("should apply 50% cursed surcharge to the cursed item only -- cursed sword (100 + 50) + plain amulet (60) = 210 before modifiers + 5 = 215");

  it.todo("should apply 30% high-enchantment surcharge for enchantment >= 5 -- sword ench 5: 100 + 30 + 5 = 135");

  it.todo("should apply 20% loyalty discount for >= 2 years with MHPCO -- sword, 2 years: 100 - 20 + 5 = 85");

  it.todo("should apply 10% first insurance surcharge -- sword, new customer: 100 + 10 + 5 = 115");

  it.todo("should apply 15% follow-up contract discount -- sword, not first: 100 - 15 + 5 = 90");

  it.todo("should apply item-specific and policy-wide modifiers correctly -- cursed sword (100+50) + plain amulet (60) + first-insurance (16) + fee 5 = 231");

  it.todo("should apply loyalty discount at exactly 2 years -- sword, 2 years: 85");

  it.todo("should apply high-enchantment surcharge at exactly enchantment 5 -- sword: 135");

  it.todo("should NOT apply high-enchantment surcharge at enchantment 4 -- sword, ench 4: 105");

  it.todo("should apply both curse and high-enchantment surcharges -- cursed sword ench 5: 100+50+30+5 = 185");

  it.todo("should calculate newcomer with cursed sword -- 0 years, no prev: 100+50+10+5 = 165");

  it.todo("should calculate long-standing customer 2nd contract with cursed sword ench 7 -- 3 years, 2nd quote: 100+50+30-20+10-15+5 = 160");
});

describe("Claim Office - Claim", () => {
  it.todo("should pay damage minus 100 G deductible for standard item -- steel sword ench 3, damage 500: payout 400");

  it.todo("should apply deductible per damaged item -- dragon attack on sword (500) + amulet (300): payout 600");

  it.todo("should reimburse at 50% for enchantment >= 8 -- sword ench 9, damage 1000: payout 400 (500-100)");

  it.todo("should fully reimburse dragon material items -- dragon sword ench 5, damage 800: payout 700 (800-100)");

  it.todo("should use 50% rule over dragon material when both apply -- dragon sword ench 9, damage 1000: payout 400 (500-100)");

  it.todo("should apply cap -- first claim 1500 -> payout 1400, cap 600; second claim: payout 600, cap 0");

  it.todo("should handle multiple same-type items -- 2 swords, cap 4000; damages each treated separately");

  it.todo("should reject claim with more damages than insured items of a type -- 2 damages for 1 sword: reject");

  it.todo("should handle rune claims -- rune (no enchantment/material), damage 200: payout 100");
});

describe("Claim Office - Errors", () => {
  it.todo("should exit with error for unknown item type in quote -- {type: 'broomstick'}");

  it.todo("should exit with error for claim referencing item not in policy");

  it.todo("should exit with error for claim with negative damage amount");
});

