function calculateQuote(items: ItemInput[]): { premium: number } {
  return { premium: 5 };
}

export function processScenario(input: ScenarioInput): ScenarioOutput {
  const results = input.steps.map((step) => {
    if (step.op === "quote") {
      return calculateQuote(step.items);
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
}

